using System.ComponentModel;using System.Runtime.CompilerServices;using System.Windows.Input;
namespace MessagingServerManager.App;
public abstract class ObservableObject:INotifyPropertyChanged{public event PropertyChangedEventHandler? PropertyChanged;protected bool Set<T>(ref T field,T value,[CallerMemberName]string? name=null){if(EqualityComparer<T>.Default.Equals(field,value))return false;field=value;PropertyChanged?.Invoke(this,new(name));return true;}protected void Raise([CallerMemberName]string? name=null)=>PropertyChanged?.Invoke(this,new(name));}
public sealed class RelayCommand(Action execute,Func<bool>? can=null):ICommand{public event EventHandler? CanExecuteChanged;public bool CanExecute(object? p)=>can?.Invoke()??true;public void Execute(object? p)=>execute();public void Raise()=>CanExecuteChanged?.Invoke(this,EventArgs.Empty);}
public sealed class AsyncRelayCommand(Func<Task> execute,Func<bool>? can=null):ICommand{bool running;public event EventHandler? CanExecuteChanged;public bool CanExecute(object? p)=>!running&&(can?.Invoke()??true);public async void Execute(object? p){running=true;Raise();try{await execute();}finally{running=false;Raise();}}public void Raise()=>CanExecuteChanged?.Invoke(this,EventArgs.Empty);}
